// Ashby public job board API — no auth required.
// GraphQL POST to https://jobs.ashbyhq.com/api/non-authenticated-graphql
// Add company slugs here. Find slugs at: https://jobs.ashbyhq.com/{slug}
const companies = [
  'vercel',
  'linear',
  'clerk',
  'posthog',
  'cal.com',
  'resend',
  'novu',
  'trigger.dev',
  'liveblocks',
  'raycast',
  'plain',
  'incident.io',
  'sequin',
  'knock',
  'infisical',
];
return companies.map(slug => ({ json: { slug } }));

function stripHtml(html) {
  return (html || '').replace(/<[^>]*>/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ').replace(/&#39;/g, "'").replace(/&quot;/g, '"').replace(/\s+/g, ' ').trim();
}
const postings = (($json.data || {}).jobBoard || {}).jobPostings || [];
// Get the company slug from the paired Companies node item
const companySlug = ($('Companies').item.json.slug || '');
return postings.map(j => ({
  json: {
    source: 'ashby',
    external_id: String(j.id ?? ''),
    company: companySlug,
    title: (j.title || '').trim(),
    location: j.locationName || '',
    remote: j.isRemote ? 'remote' : 'unknown',
    url: 'https://jobs.ashbyhq.com/' + companySlug + '/' + j.id,
    description: stripHtml(j.descriptionHtml || '').slice(0, 8000),
    posted_at: j.updatedAt || null,
  }
}));

function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(16).padStart(8, '0');
}
return items.map(({ json }) => {
  const base = [json.source, json.external_id, json.company, json.title, json.url].join('|');
  return { json: { ...json, content_hash: simpleHash(base) } };
});
